<?php
namespace Database\Seeders;
use App\Models\Announcement;use App\Models\AnnouncementCategory;use App\Models\GuildUnion;use App\Models\User;use Illuminate\Database\Seeder;
class AnnouncementSeeder extends Seeder{public function run():void{$admin=User::first();$cat=AnnouncementCategory::firstOrCreate(['slug'=>'public-notices'],['title'=>'اطلاعیه عمومی','is_active'=>true]);$unions=GuildUnion::all()->values();$titles=['اطلاعیه تمدید پروانه کسب','اطلاعیه ساعات کاری اتحادیه‌ها','اطلاعیه ثبت‌نام دوره آموزشی','اطلاعیه ارسال مدارک صنفی','اطلاعیه به‌روزرسانی اطلاعات واحدها','اطلاعیه رعایت ضوابط بهداشتی بازار','فراخوان حضور در جلسه آموزشی اصناف','اطلاعیه تعطیلی مناسبتی دبیرخانه'];foreach($titles as $i=>$title){Announcement::updateOrCreate(['slug'=>'announcement-'.($i+1)],['title'=>$title,'excerpt'=>'اطلاعیه مهم اتاق اصناف شهرستان گرگان برای فعالان صنفی.','body'=>'<p>متن کامل اطلاعیه از پایگاه داده خوانده می‌شود و توسط مدیر سامانه قابل ویرایش است.</p>','featured_image'=>'assets/img/asnaf-gorgan-default.jpg','category_id'=>$cat->id,'union_id'=>$unions->isNotEmpty()?$unions[$i%$unions->count()]->id:null,'starts_at'=>now()->subDays(2),'expires_at'=>now()->addMonth(),'is_important'=>$i<4,'show_on_home'=>true,'status'=>'published','published_at'=>now()->subDays($i),'created_by'=>$admin?->id,'approved_by'=>$admin?->id,'sort_order'=>$i+1,'is_active'=>true]);}}}
